vec3 ToneTF(vec3 x)
{
    vec3 a = (x            + 0.0822192) * x;
    vec3 b = (x * 0.983521 + 0.5001330) * x + 0.274064;

    return a / b;
}

vec3 Tonemap(vec3 acescg)
{
    vec3 color = acescg * RRT_SAT;

    color = ToneTF(color);

    color = color * ACESOutputMat;

    return color;
}

